using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;

// ── Configuration ──────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ── Tools ──────────────────────────────────────────────────────────────────────
var notebook = new ResearchNotebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        WebSearchTool.SearchAsync,
        nameof(WebSearchTool.SearchAsync),
        "Search the web for information on a query. Returns a list of results with titles, snippets, and URLs."),

    AIFunctionFactory.Create(
        notebook.AddNote,
        nameof(notebook.AddNote),
        "Save a research note with a title and body. Use this to record important findings."),

    AIFunctionFactory.Create(
        notebook.GetNotes,
        nameof(notebook.GetNotes),
        "Retrieve all saved research notes so far."),
};

// ── Build the agent ────────────────────────────────────────────────────────────
const string instructions = """
    You are a research agent. Your goal is to thoroughly research a topic the user
    asks about by using the available tools.

    Follow this workflow:
    1. Break the topic into 2-3 key sub-questions.
    2. Use the web search tool to find information for each sub-question.
    3. Save important findings using the note-taking tool.
    4. After gathering enough information, retrieve your notes and produce a
       well-structured summary with sections, key facts, and source URLs.

    Always cite sources. Be thorough but concise.
    """;

var agent = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .BuildAIAgent(
        instructions: instructions,
        name: "ResearchAgent",
        description: "An agent that researches topics using web search and note-taking.",
        tools: tools.ToList());

// ── Run the agent ──────────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       Research Agent (type 'exit' to quit)║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();

    var runOptions = new ChatClientAgentRunOptions
    {
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
        },
    };

    var session = await agent.CreateSessionAsync();

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\n🔍 Researching...\n");
    Console.ResetColor();

    try
    {
        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}",
            session,
            runOptions);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("── Research Summary ──────────────────────────────────────────");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

// ── Web Search Tool ────────────────────────────────────────────────────────────
static class WebSearchTool
{
    private static readonly HttpClient s_http = new();

    /// <summary>Searches the web and returns result snippets.</summary>
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        // Use DuckDuckGo Instant Answer API (free, no key required)
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var json = await s_http.GetStringAsync(url, cancellationToken);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new StringBuilder();

            // Abstract (main answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.AppendLine($"## {root.GetProperty("AbstractSource").GetString()}");
                results.AppendLine(abstractText);
                results.AppendLine($"Source: {abstractUrl}");
                results.AppendLine();
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                var count = 0;
                foreach (var topic in topics.EnumerateArray())
                {
                    if (count >= 8) break;
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.AppendLine($"- {text}");
                        if (!string.IsNullOrWhiteSpace(firstUrl))
                            results.AppendLine($"  URL: {firstUrl}");
                        count++;
                    }
                }
            }

            return results.Length > 0
                ? results.ToString()
                : "No results found. Try a different or more specific search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

// ── Note-Taking Tool ───────────────────────────────────────────────────────────
sealed class ResearchNotebook
{
    private readonly List<(string Title, string Body)> _notes = [];

    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("The note content with key findings")] string body)
    {
        _notes.Add((title, body));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"### Note {i + 1}: {_notes[i].Title}");
            sb.AppendLine(_notes[i].Body);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

